module shift_register(  
    input wire clk,  
    input wire reset,  
    input wire [7:0] data_in,  
    output reg serial_out  
);  
    reg [7:0] unused_shift_reg;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            unused_shift_reg <= 8'b0;  
        end else begin  
            unused_shift_reg <= {unused_shift_reg[6:0], data_in[0]};  
        end  
    end  

    always @(unused_shift_reg) begin  
        serial_out <= unused_shift_reg[0];  
    end  
endmodule
